nd malignant (malignant mesothelioma) and thus can aid in the identification of mesothelioma.2</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/1986/HBME-1_HBME-1" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','HBME-1 on pleura.','https://www.cellmarque.com/antibodies/CM/1986/HBME-1_HBME-1','#','https://www.cellmarque.com/cmsial-images/TH_283M-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-1986-hbme-1-hbme-1-47F36A3E',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','Y',null,'CM/1986/HBME-1_HBME-1');
