-5 Note:This product is in obsolescence.Myeloperoxidase (SP72)is available as an alternative.</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/118/Myeloperoxidase_Polyclonal" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Myelocytes in bone marrow are labelled by anti-myeloperoxidase.','https://www.cellmarque.com/antibodies/CM/118/Myeloperoxidase_Polyclonal','#','https://www.cellmarque.com/cmsial-images/TH_289A-7-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-118-myeloperoxidase-polyclonal-68F8D74C',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','Y',null,'CM/118/Myeloperoxidase_Polyclonal');
