<tr><td class="width-40 center-bullet "><i class="fa-custom fa-circle font-8 main-color"></i></td><td>0.2 ml</td></tr>
<tr><td class="width-40 center-bullet "><i class="fa-custom fa-circle font-8 main-color"></i></td><td>Cat. No:  PCR00802-EN</td></tr>
</tbody></table>
</div>
