ody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/1996/CD2_MRQ-11" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Interfollicular T-lymphocytes show CD2 expression in a cytoplasmic reaction.','https://www.cellmarque.com/antibodies/CM/1996/CD2_MRQ-11','#','https://www.cellmarque.com/cmsial-images/TH_102M-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-1996-cd2-mrq-11-E08B848F',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','Y',null,'CM/1996/CD2_MRQ-11');
