<tr><td class="width-40 center-bullet "><i class="fa-custom fa-circle font-8 main-color"></i></td><td>Molecular Biology Molecular Biology</td></tr>
<tr><td class="width-40 center-bullet "><i class="fa-custom fa-circle font-8 main-color"></i></td><td>Next-Generation Sequencing Next-Generation Sequencing</td></tr>
<tr><td class="width-40 center-bullet "><i class="fa-custom fa-circle font-8 main-color"></i></td><td>Cell and Protein Research Cell and Protein Research</td></tr>
</tbody></table>
</div>


<div class="panel-body">
