 testis.</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/3527/SALL4_EP299" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','SALL4 (EP299) on seminoma','https://www.cellmarque.com/antibodies/CM/3527/SALL4_EP299','#','https://www.cellmarque.com/cmsial-images/TH_385R-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-3527-sall4-ep299-464DBD77',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','Y',null,'CM/3527/SALL4_EP299');
