umors.3-9</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/3529/Inhibin-alpha_MRQ-63" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Inhibin, alpha (MRQ-63) on adrenal cortical carcinoma','https://www.cellmarque.com/antibodies/CM/3529/Inhibin-alpha_MRQ-63','#','https://www.cellmarque.com/cmsial-images/TH_271R-2-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-3529-inhibin-alpha-mrq-63-94E87573',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','Y',null,'CM/3529/Inhibin-alpha_MRQ-63');
