 </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/3177/Glucagon_EP74" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Glucagon (EP74) on pancreatic neuroendocrine tumor.','https://www.cellmarque.com/antibodies/CM/3177/Glucagon_EP74','#','https://www.cellmarque.com/cmsial-images/TH_259R-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-3177-glucagon-ep74-35E9F9C9',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','Y',null,'CM/3177/Glucagon_EP74');
