div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/71/Cytokeratin-LMW_AE1" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Cytokeratin, LMW (AE1) on prostate.','https://www.cellmarque.com/antibodies/CM/71/Cytokeratin-LMW_AE1','#','https://www.cellmarque.com/cmsial-images/TH_301M-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-71-cytokeratin-lmw-ae1-C9555166',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','Y',null,'CM/71/Cytokeratin-LMW_AE1');
Insert into WEB.PRODUCTS (DELETED,ACTIVE,PRODUCT_ID,PRODUCT_NAME,PRODUCT_NAME_WEB,SHORT_NAME,PRODUCT_SIPPLIER_ORDER,SUPPLIER_ID,DISCIPLINE,PRODUCT_GROUP,PRODUCT_TYPE,CLASS_ID,CLASS_COLOUR,ABOUT_1,ABOUT_2,PRODUCT_LINK,PRODUCT_ENQUIRE,PRODUCT_IMAGE_LARGE,PRODUCT_IMAGE_SMALL,PRODUCT_IMAGE_1,PRODUCT_IMAGE_2,PRODUCT_IMAGE_3,PRODUCT_IMAGE_4,PRODUCT_PARENT_ID,DATE_CREATED,DATE_DELETED,ANCHOR_ID,PRODUCT_IMAGE_LARGE_WIDTH,PRODUCT_IMAGE_LARGE_HEIGHT,PRODUCT_IMAGE_SMALL_WIDTH,PRODUCT_IMAGE_SMALL_HEIGHT,SUPPLIER_NAME,DISCIPLINE_ID,PRODUCT_GROUP_ID,PRODUCT_TYPE_ID,PRODUCT_GROUP_TYPE_ALT,PRODUCT_GROUP_TYPE_ALT_ID,BUSINESS,PRODUCT_IMAGE_EXTERNAL,PROUDUCT_SKU,SUPPLIER_PRODUCT_ID) values ('N','Y','PRD-7709','IMP3',null,null,null,'SUP-0003','Histopathology','Antibodies','Reagents',null,null,'<div class="antibody-outer-wrap ">  <div class="antibody-drawer-box">    <div class="antibody-info-table-wrap">      <table class="antibody-info-table">        <tr><th>Clone:</th><td>EP286</td></tr>        <tr><th>Brand:</th><td>CM + RabMAb</td></tr>        <tr><th>Host:</th><td>Rabbit</td></tr>        <tr><th>Antibody Type:</th><td>Monoclonal</td></tr>        <tr><th>Specialties:</th><td>Cytopathology • Anatomic Pathology</td></tr>        <tr><th>Visualization:</th><td>cytoplasmic, membranous</td></tr>        <tr><th>Control:</th><td>pancreatic ductal adenocarcinoma, placenta</td></tr>        <tr><th>Dilution Range:</th><td>1:25-1:100*</td></tr>        <tr>          <td colspan="2" class="antibody-details-cell">            <div class="antibody-vis-label"><strong>Details:</strong></div>            <div class="antibody-desc">Insulin-like growth factor II mRNA binding protein 3 (IMP3) is an oncofetal RNA-binding protein that regulates targets such as insulin-like growth factor-2 and beta-actin. IMP3 expression is at its highest during embryogenesis and silenced in normal human tissues (fibroblasts, lymphocytes, and testes are exceptions).1IMP3 plays a major role in early embryogenesis involving the development of the intestine, thymus, pancreas, and kidneys.2IMP3 mRNA transcript and protein have been demonstrated in high levels in pancreatic cancer tissues but not in benign lesions of the pancreas, chronic pancreatitis, or normal pancreatic tissues.1In a study of IMP3 being used to distinguish between pancreatic ductal adenocarcinoma from chronic sclerosing pancreatitis, IMP3 was found to have high sensitivity and specificity for pancreatic ductal adenocarcinoma and detected pancreatic ductal adenocarcinoma metastases.2IMP3 expression has also been found in a variety of other human cancers including renal cell carcinoma, adenocarcinoma of the uterine cervix, endometrial carcinoma, adenocarcinoma of the esophagus, malignant melanoma, Merkel cell carcinoma, urothelial carcinoma, neuroendocrine carcinoma of the lung, adenocarcinoma of the pancreas, and triple negative breast cancer.1,2</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/3149/IMP3_EP286" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Cytoplasmic labelling by IMP3 antibody on pancreatic ductal adenocarcinoma.','https://www.cellmarque.com/antibodies/CM/3149/IMP3_EP286','#','https://www.cellmarque.com/cmsial-images/TH_433R-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-3149-imp3-ep286-5175E946',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','Y',null,'CM/3149/IMP3_EP286');
Insert into WEB.PRODUCTS (DELETED,ACTIVE,PRODUCT_ID,PRODUCT_NAME,PRODUCT_NAME_WEB,SHORT_NAME,PRODUCT_SIPPLIER_ORDER,SUPPLIER_ID,DISCIPLINE,PRODUCT_GROUP,PRODUCT_TYPE,CLASS_ID,CLASS_COLOUR,ABOUT_1,ABOUT_2,PRODUCT_LINK,PRODUCT_ENQUIRE,PRODUCT_IMAGE_LARGE,PRODUCT_IMAGE_SMALL,PRODUCT_IMAGE_1,PRODUCT_IMAGE_2,PRODUCT_IMAGE_3,PRODUCT_IMAGE_4,PRODUCT_PARENT_ID,DATE_CREATED,DATE_DELETED,ANCHOR_ID,PRODUCT_IMAGE_LARGE_WIDTH,PRODUCT_IMAGE_LARGE_HEIGHT,PRODUCT_IMAGE_SMALL_WIDTH,PRODUCT_IMAGE_SMALL_HEIGHT,SUPPLIER_NAME,DISCIPLINE_ID,PRODUCT_GROUP_ID,PRODUCT_TYPE_ID,PRODUCT_GROUP_TYPE_ALT,PRODUCT_GROUP_TYPE_ALT_ID,BUSINESS,PRODUCT_IMAGE_EXTERNAL,PROUDUCT_SKU,SUPPLIER_PRODUCT_ID) values ('N','Y','PRD-7711','Carbonic Anhydrase IX (CA IX)',null,null,null,'SUP-0003','Histopathology','Antibodies','Reagents',null,null,'<div class="antibody-outer-wrap ">  <div class="antibody-drawer-box">    <div class="antibody-info-table-wrap">      <table class="antibody-info-table">        <tr><th>Clone:</th><td>EP161</td></tr>        <tr><th>Brand:</th><td>CM + RabMAb</td></tr>        <tr><th>Host:</th><td>Rabbit</td></tr>        <tr><th>Antibody Type:</th><td>Monoclonal</td></tr>        <tr><th>Specialties:</th><td>Anatomic Pathology</td></tr>        <tr><th>Visualization:</th><td>membranous</td></tr>        <tr><th>Control:</th><td>clear cell renal cell carcinoma, gall bladder epithelium</td></tr>        <tr><th>Dilution Range:</th><td>1:50-1:200*</td></tr>        <tr>          <td colspan="2" class="antibody-details-cell">            <div class="antibody-vis-label"><strong>Details:</strong></div>            <div class="antibody-desc">Carbonic Anhydrase (CA IX) is part of a family of zinc containing metalloproteins that catalyze the reversible hydration of CO2.1Among these, CA IX is anchored to the cell membrane and is expressed in the human gastrointestinal tract, chiefly in the stomach.1Data suggest consistent immunoreactivity for anti-CA IX in clear cell renal cell carcinoma (RCC) making it a useful marker for this type of tumor.2</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/3152/Carbonic-Anhydrase-IX-CA-IX_EP161" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Carbonic Anhydrase IX (CA IX) (EP161) on renal cell carcinoma.','https://www.cellmarque.com/antibodies/CM/3152/Carbonic-Anhydrase-IX-CA-IX_EP161','#','https://www.cellmarque.com/cmsial-images/TH_379R-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-3152-carbonic-anhydrase-ix-ca-ix-ep16-04D1D06D',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','Y',null,'CM/3152/Carbonic-Anhydrase-IX-CA-IX_EP161');
Insert into WEB.PRODUCTS (DELETED,ACTIVE,PRODUCT_ID,PRODUCT_NAME,PRODUCT_NAME_WEB,SHORT_NAME,PRODUCT_SIPPLIER_ORDER,SUPPLIER_ID,DISCIPLINE,PRODUCT_GROUP,PRODUCT_TYPE,CLASS_ID,CLASS_COLOUR,ABOUT_1,ABOUT_2,PRODUCT_LINK,PRODUCT_ENQUIRE,PRODUCT_IMAGE_LARGE,PRODUCT_IMAGE_SMALL,PRODUCT_IMAGE_1,PRODUCT_IMAGE_2,PRODUCT_IMAGE_3,PRODUCT_IMAGE_4,PRODUCT_PARENT_ID,DATE_CREATED,DATE_DELETED,ANCHOR_ID,PRODUCT_IMAGE_LARGE_WIDTH,PRODUCT_IMAGE_LARGE_HEIGHT,PRODUCT_IMAGE_SMALL_WIDTH,PRODUCT_IMAGE_SMALL_HEIGHT,SUPPLIER_NAME,DISCIPLINE_ID,PRODUCT_GROUP_ID,PRODUCT_TYPE_ID,PRODUCT_GROUP_TYPE_ALT,PRODUCT_GROUP_TYPE_ALT_ID,BUSINESS,PRODUCT_IMAGE_EXTERNAL,PROUDUCT_SKU,SUPPLIER_PRODUCT_ID) values ('N','Y','PRD-7621','BCL2',null,null,null,'SUP-0003','Histopathology','Antibodies','Reagents',null,null,'<div class="antibody-outer-wrap ">  <div class="antibody-drawer-box">    <div class="antibody-info-table-wrap">      <table class="antibody-info-table">        <tr><th>Clone:</th><td>E17</td></tr>        <tr><th>Brand:</th><td>CM + RabMAb</td></tr>        <tr><th>Host:</th><td>Rabbit</td></tr>        <tr><th>Antibody Type:</th><td>Monoclonal</td></tr>        <tr><th>Specialties:</th><td>Hematopathology</td></tr>        <tr><th>Visualization:</th><td>cytoplasmic</td></tr>        <tr><th>Control:</th><td>tonsil</td></tr>        <tr><th>Dilution Range:</th><td>1:25-1:100*</td></tr>        <tr>          <td colspan="2" class="antibody-details-cell">            <div class="antibody-vis-label"><strong>Details:</strong></div>            <div class="antibody-desc">BCL2 is a protein associated with apoptosis regulation produced by the bcl-2 gene, located on chromosome 14q32.1BCL2 is comprised of an alpha (239 amino acids) and beta chain. BCL2 (and thus BCL2 alpha chain) is found in mitochondrial and nuclear membranes and in the cytosol rather than the cell surface. In normal lymphoid tissue, BCL2 antibody reacts with small B-lymphocytes in the mantle zone and many cells within the T-cell areas. Anti-BCL2 has shown consistent negative reaction on reactive germinal center B-cells and positive staining of neoplastic follicles in follicular lymphoma.2This antibody is valuable when distinguishing between reactive and neoplastic follicular proliferation in lymph node biopsies. This antibody may also be used in distinguishing between those follicular lymphomas that express BCL2 protein and the small number in which the neoplastic cells are BCL2 negative. Anti-BCL2 has been used as an indicator of minimal residual disease in the bone marrow of follicular lymphoma patients when staining is strong and uniform.3</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/2089/BCL2_E17" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','BCL2 antibody (clone E17) displays strong and diffuse cytoplasmic staining in in situ follicular lymphoma cells.','https://www.cellmarque.com/antibodies/CM/2089/BCL2_E17','#','https://www.cellmarque.com/cmsial-images/TH_226R-1-ihc-02.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-2089-bcl2-e17-BEE7260D',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','Y',null,'CM/2089/BCL2_E17');
Insert into WEB.PRODUCTS (DELETED,ACTIVE,PRODUCT_ID,PRODUCT_NAME,PRODUCT_NAME_WEB,SHORT_NAME,PRODUCT_SIPPLIER_ORDER,SUPPLIER_ID,DISCIPLINE,PRODUCT_GROUP,PRODUCT_TYPE,CLASS_ID,CLASS_COLOUR,ABOUT_1,ABOUT_2,PRODUCT_LINK,PRODUCT_ENQUIRE,PRODUCT_IMAGE_LARGE,PRODUCT_IMAGE_SMALL,PRODUCT_IMAGE_1,PRODUCT_IMAGE_2,PRODUCT_IMAGE_3,PRODUCT_IMAGE_4,PRODUCT_PARENT_ID,DATE_CREATED,DATE_DELETED,ANCHOR_ID,PRODUCT_IMAGE_LARGE_WIDTH,PRODUCT_IMAGE_LARGE_HEIGHT,PRODUCT_IMAGE_SMALL_WIDTH,PRODUCT_IMAGE_SMALL_HEIGHT,SUPPLIER_NAME,DISCIPLINE_ID,PRODUCT_GROUP_ID,PRODUCT_TYPE_ID,PRODUCT_GROUP_TYPE_ALT,PRODUCT_GROUP_TYPE_ALT_ID,BUSINESS,PRODUCT_IMAGE_EXTERNAL,PROUDUCT_SKU,SUPPLIER_PRODUCT_ID) values ('N','Y','PRD-7789','SMAD4',null,null,null,'SUP-0003','Histopathology','Antibodies','Reagents',null,null,'<div class="antibody-outer-wrap ">  <div class="antibody-drawer-box">    <div class="antibody-info-table-wrap">      <table class="antibody-info-table">        <tr><th>Clone:</th><td>MRQ-72</td></tr>        <tr><th>Brand:</th><td>Cell Marque</td></tr>        <tr><th>Host:</th><td>Rabbit</td></tr>        <tr><th>Antibody Type:</th><td>Monoclonal</td></tr>        <tr><th>Specialties:</th><td>Gastrointestinal (GI) Pathology</td></tr>        <tr><th>Visualization:</th><td></td></tr>        <tr><th>Control:</th><td>Pancreas (Cytoplasmic, Nuclear)</td></tr>        <tr><th>Dilution Range:</th><td>1:25-1:50*</td></tr>        <tr>          <td colspan="2" class="antibody-details-cell">            <div class="antibody-vis-label"><strong>Details:</strong></div>            <div class="antibody-desc">Mothers Against Decapentaplegic Homolog 4 (SMAD4) is a transcription factor that is involved in TGFβ signaling pathways and acts as a tumor suppressor1. SMAD4 is commonly expressed in a variety of cancers, including pancreatic ductal adenocarcinoma (PDA), colorectal carcinoma (CRC), hepatocellular carcinoma (HCC), and gastric carcinomas, as well as non-neoplastic liver, pancreas, and colon2-5. However, a loss of expression has been observed in a subset of PDA, CRC and gastric carcinomas due to a variety of mutations including nonsense, missense, deletions, and splice site changes2-4,6. In contrast, SMAD4 is over-expressed in HCC compared to the weak expression that is exhibited in non-neoplastic liver5.</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/3687/SMAD4_MRQ-72" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','SMAD4 (MRQ-72) on pancreatic tissue','https://www.cellmarque.com/antibodies/CM/3687/SMAD4_MRQ-72','#','https://www.cellmarque.com/cmsial-images/TH_487R-9-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-3687-smad4-mrq-72-814722C5',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','Y',null,'CM/3687/SMAD4_MRQ-72');
Insert into WEB.PRODUCTS (DELETED,ACTIVE,PRODUCT_ID,PRODUCT_NAME,PRODUCT_NAME_WEB,SHORT_NAME,PRODUCT_SIPPLIER_ORDER,SUPPLIER_ID,DISCIPLINE,PRODUCT_GROUP,PRODUCT_TYPE,CLASS_ID,CLASS_COLOUR,ABOUT_1,ABOUT_2,PRODUCT_LINK,PRODUCT_ENQUIRE,PRODUCT_IMAGE_LARGE,PRODUCT_IMAGE_SMALL,PRODUCT_IMAGE_1,PRODUCT_IMAGE_2,PRODUCT_IMAGE_3,PRODUCT_IMAGE_4,PRODUCT_PARENT_ID,DATE_CREATED,DATE_DELETED,ANCHOR_ID,PRODUCT_IMAGE_LARGE_WIDTH,PRODUCT_IMAGE_LARGE_HEIGHT,PRODUCT_IMAGE_SMALL_WIDTH,PRODUCT_IMAGE_SMALL_HEIGHT,SUPPLIER_NAME,DISCIPLINE_ID,PRODUCT_GROUP_ID,PRODUCT_TYPE_ID,PRODUCT_GROUP_TYPE_ALT,PRODUCT_GROUP_TYPE_ALT_ID,BUSINESS,PRODUCT_IMAGE_EXTERNAL,PROUDUCT_SKU,SUPPLIER_PRODUCT_ID) values ('N','Y','PRD-7714','IgG4',null,null,null,'SUP-0003','Histopathology','Antibodies','Reagents',null,null,'<div class="antibody-outer-wrap ">  <div class="antibody-drawer-box">    <div class="antibody-info-table-wrap">      <table class="antibody-info-table">        <tr><th>Clone:</th><td>EP138</td></tr>        <tr><th>Brand:</th><td>CM + RabMAb</td></tr>        <tr><th>Host:</th><td>Rabbit</td></tr>        <tr><th>Antibody Type:</th><td>Monoclonal</td></tr>        <tr><th>Specialties:</th><td>Gastrointestinal (GI) Pathology • Anatomic Pathology</td></tr>        <tr><th>Visualization:</th><td>cytoplasmic</td></tr>        <tr><th>Control:</th><td>tonsil</td></tr>        <tr><th>Dilution Range:</th><td>1:100-1:500*</td></tr>        <tr>          <td colspan="2" class="antibody-details-cell">            <div class="antibody-vis-label"><strong>Details:</strong></div>            <div class="antibody-desc">IgG4-related sclerosing disease has been recognized as a systemic disease entity characterized by an elevated serum IgG4 level, sclerosing fibrosis, and diffuse lymphoplasmacytic infiltration with the presence of many IgG4-positive plasma cells. Clinical manifestations are apparent in the pancreas, bile duct, gall bladder, lacrimal gland, salivary gland, retroperitoneum, kidney, lung, breast, thyroid, and prostate. Immunohistochemical analyses in the case of IgG4-related sclerosing disease not only exhibit significantly more than normal IgG4-positive plasma cells in affected tissues but also significantly higher IgG4/IgG ratios (typically > 30%).1-8 Note:This product is in obsolescence.IgG4 (MRQ-44)is available as an alternative.</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/3155/IgG4_EP138" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','IgG4 (EP138) on tonsil.','https://www.cellmarque.com/antibodies/CM/3155/IgG4_EP138','#','https://www.cellmarque.com/cmsial-images/TH_367R-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-3155-igg4-ep138-CEEA5573',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','Y',null,'CM/3155/IgG4_EP138');
Insert into WEB.PRODUCTS (DELETED,ACTIVE,PRODUCT_ID,PRODUCT_NAME,PRODUCT_NAME_WEB,SHORT_NAME,PRODUCT_SIPPLIER_ORDER,SUPPLIER_ID,DISCIPLINE,PRODUCT_GROUP,PRODUCT_TYPE,CLASS_ID,CLASS_COLOUR,ABOUT_1,ABOUT_2,PRODUCT_LINK,PRODUCT_ENQUIRE,PRODUCT_IMAGE_LARGE,PRODUCT_IMAGE_SMALL,PRODUCT_IMAGE_1,PRODUCT_IMAGE_2,PRODUCT_IMAGE_3,PRODUCT_IMAGE_4,PRODUCT_PARENT_ID,DATE_CREATED,DATE_DELETED,ANCHOR_ID,PRODUCT_IMAGE_LARGE_WIDTH,PRODUCT_IMAGE_LARGE_HEIGHT,PRODUCT_IMAGE_SMALL_WIDTH,PRODUCT_IMAGE_SMALL_HEIGHT,SUPPLIER_NAME,DISCIPLINE_ID,PRODUCT_GROUP_ID,PRODUCT_TYPE_ID,PRODUCT_GROUP_TYPE_ALT,PRODUCT_GROUP_TYPE_ALT_ID,BUSINESS,PRODUCT_IMAGE_EXTERNAL,PROUDUCT_SKU,SUPPLIER_PRODUCT_ID) values ('N','Y','PRD-7715','Neurofilament',null,null,null,'SUP-0003','Histopathology','Antibodies','Reagents',null,null,'<div class="antibody-outer-wrap ">  <div class="antibody-drawer-box">    <div class="antibody-info-table-wrap">      <table class="antibody-info-table">        <tr><th>Clone:</th><td>EP79</td></tr>        <tr><th>Brand:</th><td>CM + RabMAb</td></tr>        <tr><th>Host:</th><td>Rabbit</td></tr>        <tr><th>Antibody Type:</th><td>Monoclonal</td></tr>        <tr><th>Specialties:</th><td>Neuropathology</td></tr>        <tr><th>Visualization:</th><td>cytoplasmic</td></tr>        <tr><th>Control:</th><td>brain</td></tr>        <tr><th>Dilution Range:</th><td>1:100-1:500*</td></tr>        <tr>          <td colspan="2" class="antibody-details-cell">            <div class="antibody-vis-label"><strong>Details:</strong></div>            <div class="antibody-desc">Immunolabelling of neurofilaments (NF) is employed for study of nerve distribution of normal and abnormal tissues, and neuronal differentiation of neoplasms. NF are found in neuromas, ganglioneuromas, gangliogliomas, ganglioneuroblastomas, neuroblastomas, and retinoblastomas. Neurofilaments are also present in paragangliomas, as well as, adrenal and extra-adrenal pheochromocytomas. Carcinoids, neuroendocrine carcinomas of the skin, and lung small cell carcinoma also express neurofilament.1-5 Note:This product is in obsolescence.Neurofilament (2F11)is available as an alternative.</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/3156/Neurofilament_EP79" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Neurofilament (EP79) on glioblastoma.','https://www.cellmarque.com/antibodies/CM/3156/Neurofilament_EP79','#','https://www.cellmarque.com/cmsial-images/TH_320R-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-3156-neurofilament-ep79-C509E33C',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','Y',null,'CM/3156/Neurofilament_EP79');
