ntibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/144/Thyroglobulin_2H11-6E1" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Thyrocytes are labelled by anti-thyroglobulin.','https://www.cellmarque.com/antibodies/CM/144/Thyroglobulin_2H11-6E1','#','https://www.cellmarque.com/cmsial-images/TH_340M-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-144-thyroglobulin-2h11-6e1-B1B4CC22',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','Y',null,'CM/144/Thyroglobulin_2H11-6E1');
