      </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/17/BCA-225_Cu-18" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','BCA-225 antibody shows a moderate to strong cytoplasmic staining reaction for breast invasive ductal carcinoma, metastatic to lymph node.','https://www.cellmarque.com/antibodies/CM/17/BCA-225_Cu-18','#','https://www.cellmarque.com/cmsial-images/TH_225M-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-17-bca-225-cu-18-C15F1416',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','Y',null,'CM/17/BCA-225_Cu-18');
Insert into WEB.PRODUCTS (DELETED,ACTIVE,PRODUCT_ID,PRODUCT_NAME,PRODUCT_NAME_WEB,SHORT_NAME,PRODUCT_SIPPLIER_ORDER,SUPPLIER_ID,DISCIPLINE,PRODUCT_GROUP,PRODUCT_TYPE,CLASS_ID,CLASS_COLOUR,ABOUT_1,ABOUT_2,PRODUCT_LINK,PRODUCT_ENQUIRE,PRODUCT_IMAGE_LARGE,PRODUCT_IMAGE_SMALL,PRODUCT_IMAGE_1,PRODUCT_IMAGE_2,PRODUCT_IMAGE_3,PRODUCT_IMAGE_4,PRODUCT_PARENT_ID,DATE_CREATED,DATE_DELETED,ANCHOR_ID,PRODUCT_IMAGE_LARGE_WIDTH,PRODUCT_IMAGE_LARGE_HEIGHT,PRODUCT_IMAGE_SMALL_WIDTH,PRODUCT_IMAGE_SMALL_HEIGHT,SUPPLIER_NAME,DISCIPLINE_ID,PRODUCT_GROUP_ID,PRODUCT_TYPE_ID,PRODUCT_GROUP_TYPE_ALT,PRODUCT_GROUP_TYPE_ALT_ID,BUSINESS,PRODUCT_IMAGE_EXTERNAL,PROUDUCT_SKU,SUPPLIER_PRODUCT_ID) values ('N','Y','PRD-7520','PAX-5',null,null,null,'SUP-0003','Histopathology','Antibodies','Reagents',null,null,'<div class="antibody-outer-wrap ">  <div class="antibody-drawer-box">    <div class="antibody-info-table-wrap">      <table class="antibody-info-table">        <tr><th>Clone:</th><td>24</td></tr>        <tr><th>Brand:</th><td>Cell Marque</td></tr>        <tr><th>Host:</th><td>Mouse</td></tr>        <tr><th>Antibody Type:</th><td>Monoclonal</td></tr>        <tr><th>Specialties:</th><td>Hematopathology</td></tr>        <tr><th>Visualization:</th><td>nuclear</td></tr>        <tr><th>Control:</th><td>tonsil</td></tr>        <tr><th>Dilution Range:</th><td>1:100-1:500*</td></tr>        <tr>          <td colspan="2" class="antibody-details-cell">            <div class="antibody-vis-label"><strong>Details:</strong></div>            <div class="antibody-desc">PAX-5 encodes for B-cell-specific activator protein (BSAP), a marker for B-cells, including B-lymphoblastic neoplasms and maturation stage. It is found in most cases of mature and precursor B-cell non-Hodgkin lymphomas/leukemias. In approximately 97% of cases of classic Hodgkin lymphoma, Reed-Sternberg cells express PAX-5.4PAX-5 is not detected in multiple myeloma and solitary plasmacytoma, making it useful for such differentiation.1,3Diffuse large B-cell lymphomas do express PAX-5, save for those with terminal B-cell differentiation. T-cell neoplasms do not stain with anti-PAX-5. There is a strong association with CD20 expression.1-4</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/130/PAX-5_24" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Nuclear labelling of germinal center and mantle zone cells by PAX-5 antibody on adenoidal tissue.','https://www.cellmarque.com/antibodies/CM/130/PAX-5_24','#','https://www.cellmarque.com/cmsial-images/TH_312M-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-130-pax-5-24-B1C6B8A0',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','Y',null,'CM/130/PAX-5_24');
Insert into WEB.PRODUCTS (DELETED,ACTIVE,PRODUCT_ID,PRODUCT_NAME,PRODUCT_NAME_WEB,SHORT_NAME,PRODUCT_SIPPLIER_ORDER,SUPPLIER_ID,DISCIPLINE,PRODUCT_GROUP,PRODUCT_TYPE,CLASS_ID,CLASS_COLOUR,ABOUT_1,ABOUT_2,PRODUCT_LINK,PRODUCT_ENQUIRE,PRODUCT_IMAGE_LARGE,PRODUCT_IMAGE_SMALL,PRODUCT_IMAGE_1,PRODUCT_IMAGE_2,PRODUCT_IMAGE_3,PRODUCT_IMAGE_4,PRODUCT_PARENT_ID,DATE_CREATED,DATE_DELETED,ANCHOR_ID,PRODUCT_IMAGE_LARGE_WIDTH,PRODUCT_IMAGE_LARGE_HEIGHT,PRODUCT_IMAGE_SMALL_WIDTH,PRODUCT_IMAGE_SMALL_HEIGHT,SUPPLIER_NAME,DISCIPLINE_ID,PRODUCT_GROUP_ID,PRODUCT_TYPE_ID,PRODUCT_GROUP_TYPE_ALT,PRODUCT_GROUP_TYPE_ALT_ID,BUSINESS,PRODUCT_IMAGE_EXTERNAL,PROUDUCT_SKU,SUPPLIER_PRODUCT_ID) values ('N','Y','PRD-7634','p53',null,null,null,'SUP-0003','Histopathology','Antibodies','Reagents',null,null,'<div class="antibody-outer-wrap ">  <div class="antibody-drawer-box">    <div class="antibody-info-table-wrap">      <table class="antibody-info-table">        <tr><th>Clone:</th><td>SP5</td></tr>        <tr><th>Brand:</th><td>Cell Marque</td></tr>        <tr><th>Host:</th><td>Rabbit</td></tr>        <tr><th>Antibody Type:</th><td>Monoclonal</td></tr>        <tr><th>Specialties:</th><td>Anatomic Pathology</td></tr>        <tr><th>Visualization:</th><td>nuclear</td></tr>        <tr><th>Control:</th><td>colon carcinoma</td></tr>        <tr><th>Dilution Range:</th><td>1:25-1:100*</td></tr>        <tr>          <td colspan="2" class="antibody-details-cell">            <div class="antibody-vis-label"><strong>Details:</strong></div>            <div class="antibody-desc">Anti-p53 tumor suppressor protein antibody recognizes a 53 kDa phosphoprotein, identified as p53 suppressor gene product. It reacts with the mutant as well as wild type p53.1Positive nuclear staining with this antibody has been shown to be a factor in breast carcinoma, lung carcinoma, colorectal carcinoma, urothelial carcinoma, and ependymoma.2-8Anti-p53 positivity has also been used to differentiate uterine serous carcinoma from endometrioid carcinoma, as well as a marker for intratubular germ cell neoplasia.9 Note:This product is in obsolescence.p53 (DO7)is available as an alternative.</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/2108/p53_SP5" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Nuclear staining of tumor cells by p53 antibody in colon adenocarcinoma.','https://www.cellmarque.com/antibodies/CM/2108/p53_SP5','#','https://www.cellmarque.com/cmsial-images/TH_453R-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-2108-p53-sp5-93C4F211',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','Y',null,'CM/2108/p53_SP5');
Insert into WEB.PRODUCTS (DELETED,ACTIVE,PRODUCT_ID,PRODUCT_NAME,PRODUCT_NAME_WEB,SHORT_NAME,PRODUCT_SIPPLIER_ORDER,SUPPLIER_ID,DISCIPLINE,PRODUCT_GROUP,PRODUCT_TYPE,CLASS_ID,CLASS_COLOUR,ABOUT_1,ABOUT_2,PRODUCT_LINK,PRODUCT_ENQUIRE,PRODUCT_IMAGE_LARGE,PRODUCT_IMAGE_SMALL,PRODUCT_IMAGE_1,PRODUCT_IMAGE_2,PRODUCT_IMAGE_3,PRODUCT_IMAGE_4,PRODUCT_PARENT_ID,DATE_CREATED,DATE_DELETED,ANCHOR_ID,PRODUCT_IMAGE_LARGE_WIDTH,PRODUCT_IMAGE_LARGE_HEIGHT,PRODUCT_IMAGE_SMALL_WIDTH,PRODUCT_IMAGE_SMALL_HEIGHT,SUPPLIER_NAME,DISCIPLINE_ID,PRODUCT_GROUP_ID,PRODUCT_TYPE_ID,PRODUCT_GROUP_TYPE_ALT,PRODUCT_GROUP_TYPE_ALT_ID,BUSINESS,PRODUCT_IMAGE_EXTERNAL,PROUDUCT_SKU,SUPPLIER_PRODUCT_ID) values ('N','Y','PRD-7635','Phosphohistone H3 (PHH3)',null,null,null,'SUP-0003','Histopathology','Antibodies','Reagents',null,null,'<div class="antibody-outer-wrap ">  <div class="antibody-drawer-box">    <div class="antibody-info-table-wrap">      <table class="antibody-info-table">        <tr><th>Clone:</th><td>Polyclonal</td></tr>        <tr><th>Brand:</th><td>Cell Marque</td></tr>        <tr><th>Host:</th><td>Rabbit</td></tr>        <tr><th>Antibody Type:</th><td>Polyclonal</td></tr>        <tr><th>Specialties:</th><td>Anatomic Pathology</td></tr>        <tr><th>Visualization:</th><td></td></tr>        <tr><th>Control:</th><td>Tonsil (Nuclear)</td></tr>        <tr><th>Dilution Range:</th><td>1:100-1:500*</td></tr>        <tr>          <td colspan="2" class="antibody-details-cell">            <div class="antibody-vis-label"><strong>Details:</strong></div>            <div class="antibody-desc">Phosphohistone H3 (PHH3) is a core histone protein, which together with other histones, forms the major protein constituents of the chromatin in eukaryotic cells. In mammalian cells, phosphohistone H3 is negligible during interphase but reaches a maximum for chromatin condensation during mitosis.1Immunohistochemical studies showed anti-PHH3 specifically detected the core protein histone H3 only when phosphorylated at serine 10 or serine 28. Studies have also revealed no phosphorylation on the histone H3 during apoptosis.2PHH3 can serve as a mitotic marker to separate mitotic figures from apoptotic bodies and karyorrhectic debris, which may be a very useful tool in diagnosis of tumor grades, especially in CNS, skin, soft tissue, and GIST.3,4,5</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/2110/Phosphohistone-H3-PHH3_Polyclonal" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Mitotic figures labelled by the phosphohistone H3 antibody.','https://www.cellmarque.com/antibodies/CM/2110/Phosphohistone-H3-PHH3_Polyclonal','#','https://www.cellmarque.com/cmsial-images/TH_369A-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-2110-phosphohistone-h3-phh3-polyclona-FC96F938',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','Y',null,'CM/2110/Phosphohistone-H3-PHH3_Polyclonal');
