v>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/2128/SOX-2_SP76" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Squamous cell carcinoma of lung is expressed by SOX-2 antibody in a nuclear pattern.','https://www.cellmarque.com/antibodies/CM/2128/SOX-2_SP76','#','https://www.cellmarque.com/cmsial-images/TH_371R-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-2128-sox-2-sp76-ED23BF8B',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','Y',null,'CM/2128/SOX-2_SP76');
