   <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Spectrin antibody labels red blood cell precursors with a membranous pattern.','https://www.cellmarque.com/antibodies/CM/140/Spectrin_RBC2-3D5','#','https://www.cellmarque.com/cmsial-images/TH_333M-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-140-spectrin-rbc2-3d5-A92C9C26',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','Y',null,'CM/140/Spectrin_RBC2-3D5');
