pressed markers of mature naive B-cell activation and it is useful in identifying functional mature B-lymphocyte subsets.1-3</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/2138/CD38_SP149" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','CD38 (SP149) on bone marrow.','https://www.cellmarque.com/antibodies/CM/2138/CD38_SP149','#','https://www.cellmarque.com/cmsial-images/TH_118R-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-2138-cd38-sp149-A57BA55A',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','Y',null,'CM/2138/CD38_SP149');
Insert into WEB.PRODUCTS (DELETED,ACTIVE,PRODUCT_ID,PRODUCT_NAME,PRODUCT_NAME_WEB,SHORT_NAME,PRODUCT_SIPPLIER_ORDER,SUPPLIER_ID,DISCIPLINE,PRODUCT_GROUP,PRODUCT_TYPE,CLASS_ID,CLASS_COLOUR,ABOUT_1,ABOUT_2,PRODUCT_LINK,PRODUCT_ENQUIRE,PRODUCT_IMAGE_LARGE,PRODUCT_IMAGE_SMALL,PRODUCT_IMAGE_1,PRODUCT_IMAGE_2,PRODUCT_IMAGE_3,PRODUCT_IMAGE_4,PRODUCT_PARENT_ID,DATE_CREATED,DATE_DELETED,ANCHOR_ID,PRODUCT_IMAGE_LARGE_WIDTH,PRODUCT_IMAGE_LARGE_HEIGHT,PRODUCT_IMAGE_SMALL_WIDTH,PRODUCT_IMAGE_SMALL_HEIGHT,SUPPLIER_NAME,DISCIPLINE_ID,PRODUCT_GROUP_ID,PRODUCT_TYPE_ID,PRODUCT_GROUP_TYPE_ALT,PRODUCT_GROUP_TYPE_ALT_ID,BUSINESS,PRODUCT_IMAGE_EXTERNAL,PROUDUCT_SKU,SUPPLIER_PRODUCT_ID) values ('N','Y','PRD-7669','GATA3',null,null,null,'SUP-0003','Histopathology','Antibodies','Reagents',null,null,'<div class="antibody-outer-wrap ">  <div class="antibody-drawer-box">    <div class="antibody-info-table-wrap">      <table class="antibody-info-table">        <tr><th>Clone:</th><td>L50-823</td></tr>        <tr><th>Brand:</th><td>Cell Marque</td></tr>        <tr><th>Host:</th><td>Mouse</td></tr>        <tr><th>Antibody Type:</th><td>Monoclonal</td></tr>        <tr><th>Specialties:</th><td>Anatomic Pathology • Breast/Gynecological Pathology • Genitourinary (GU) Pathology</td></tr>        <tr><th>Visualization:</th><td></td></tr>        <tr><th>Control:</th><td>Breast carcinoma (Nuclear); Urothelial carcinoma (Nuclear)</td></tr>        <tr><th>Dilution Range:</th><td>1:100-1:500*</td></tr>        <tr>          <td colspan="2" class="antibody-details-cell">            <div class="antibody-vis-label"><strong>Details:</strong></div>            <div class="antibody-desc">GATA binding protein 3 or GATA3, is a zinc finger transcription factor and plays an important role in promoting and directing cell proliferation, development, and differentiation in many tissues and cell types.1-4The human GATA3 gene has been mapped to chromosome 10p15.3GATA3 expression is primarily seen in breast carcinoma and urothelial carcinoma.1-2Anti-GATA3 can also be useful in the identification of unknown primary carcinoma when carcinomas of the breast or bladder are a possibility.</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/2157/GATA3_L50-823" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Mouse monoclonal anti-GATA3 demonstrates a strong diffuse and nuclear reaction in neoplastic cells of invasive ductal carcinoma of the breast.','https://www.cellmarque.com/antibodies/CM/2157/GATA3_L50-823','#','https://www.cellmarque.com/cmsial-images/TH_390M-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-2157-gata3-l50-823-1CD6D94B',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','Y',null,'CM/2157/GATA3_L50-823');
