</table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/182/MART-1-M2-7C10-Tyrosinase-T311" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','MART-1 (Melan A) + Tyrosinase (M2-7C10 + T311) on melanoma.','https://www.cellmarque.com/antibodies/CM/182/MART-1-M2-7C10-Tyrosinase-T311','#','https://www.cellmarque.com/cmsial-images/TH_903H-0-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-182-mart-1-m2-7c10-tyrosinase-t311-D810E20B',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','Y',null,'CM/182/MART-1-M2-7C10-Tyrosinase-T311');
Insert into WEB.PRODUCTS (DELETED,ACTIVE,PRODUCT_ID,PRODUCT_NAME,PRODUCT_NAME_WEB,SHORT_NAME,PRODUCT_SIPPLIER_ORDER,SUPPLIER_ID,DISCIPLINE,PRODUCT_GROUP,PRODUCT_TYPE,CLASS_ID,CLASS_COLOUR,ABOUT_1,ABOUT_2,PRODUCT_LINK,PRODUCT_ENQUIRE,PRODUCT_IMAGE_LARGE,PRODUCT_IMAGE_SMALL,PRODUCT_IMAGE_1,PRODUCT_IMAGE_2,PRODUCT_IMAGE_3,PRODUCT_IMAGE_4,PRODUCT_PARENT_ID,DATE_CREATED,DATE_DELETED,ANCHOR_ID,PRODUCT_IMAGE_LARGE_WIDTH,PRODUCT_IMAGE_LARGE_HEIGHT,PRODUCT_IMAGE_SMALL_WIDTH,PRODUCT_IMAGE_SMALL_HEIGHT,SUPPLIER_NAME,DISCIPLINE_ID,PRODUCT_GROUP_ID,PRODUCT_TYPE_ID,PRODUCT_GROUP_TYPE_ALT,PRODUCT_GROUP_TYPE_ALT_ID,BUSINESS,PRODUCT_IMAGE_EXTERNAL,PROUDUCT_SKU,SUPPLIER_PRODUCT_ID) values ('N','Y','PRD-7657','C4d',null,null,null,'SUP-0003','Histopathology','Antibodies','Reagents',null,null,'<div class="antibody-outer-wrap ">  <div class="antibody-drawer-box">    <div class="antibody-info-table-wrap">      <table class="antibody-info-table">        <tr><th>Clone:</th><td>SP91</td></tr>        <tr><th>Brand:</th><td>Cell Marque</td></tr>        <tr><th>Host:</th><td>Rabbit</td></tr>        <tr><th>Antibody Type:</th><td>Monoclonal</td></tr>        <tr><th>Specialties:</th><td>Anatomic Pathology</td></tr>        <tr><th>Visualization:</th><td></td></tr>        <tr><th>Control:</th><td>Lymph node (Cytoplasmic, Membranous); Tonsil (Cytoplasmic, Membranous); Acute rejected kidney transplant (Cytoplasmic, Membranous)</td></tr>        <tr><th>Dilution Range:</th><td>1:50-1:200*</td></tr>        <tr>          <td colspan="2" class="antibody-details-cell">            <div class="antibody-vis-label"><strong>Details:</strong></div>            <div class="antibody-desc">Acute humoral rejection is mediated by antibodies to the donor endothelium that activate the classical complement pathway.1-3This leads to a number of split products of complement proteins. C4d is a fragment of C 4 complement released during activation of the classic complement pathway by the antigen antibody complex.3C4d deposits in peritubular capillaries and is regarded as an indirect sign of an antibody response.3,6C4d can be a useful tool for indicating acute renal allograft rejection.1-6</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/2140/C4d_SP91" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','C4d (SP91) on acute rejected kidney.','https://www.cellmarque.com/antibodies/CM/2140/C4d_SP91','#','https://www.cellmarque.com/cmsial-images/TH_404R-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-2140-c4d-sp91-F838C776',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','Y',null,'CM/2140/C4d_SP91');
Insert into WEB.PRODUCTS (DELETED,ACTIVE,PRODUCT_ID,PRODUCT_NAME,PRODUCT_NAME_WEB,SHORT_NAME,PRODUCT_SIPPLIER_ORDER,SUPPLIER_ID,DISCIPLINE,PRODUCT_GROUP,PRODUCT_TYPE,CLASS_ID,CLASS_COLOUR,ABOUT_1,ABOUT_2,PRODUCT_LINK,PRODUCT_ENQUIRE,PRODUCT_IMAGE_LARGE,PRODUCT_IMAGE_SMALL,PRODUCT_IMAGE_1,PRODUCT_IMAGE_2,PRODUCT_IMAGE_3,PRODUCT_IMAGE_4,PRODUCT_PARENT_ID,DATE_CREATED,DATE_DELETED,ANCHOR_ID,PRODUCT_IMAGE_LARGE_WIDTH,PRODUCT_IMAGE_LARGE_HEIGHT,PRODUCT_IMAGE_SMALL_WIDTH,PRODUCT_IMAGE_SMALL_HEIGHT,SUPPLIER_NAME,DISCIPLINE_ID,PRODUCT_GROUP_ID,PRODUCT_TYPE_ID,PRODUCT_GROUP_TYPE_ALT,PRODUCT_GROUP_TYPE_ALT_ID,BUSINESS,PRODUCT_IMAGE_EXTERNAL,PROUDUCT_SKU,SUPPLIER_PRODUCT_ID) values ('N','Y','PRD-7658','CD7',null,null,null,'SUP-0003','Histopathology','Antibodies','Reagents',null,null,'<div class="antibody-outer-wrap ">  <div class="antibody-drawer-box">    <div class="antibody-info-table-wrap">      <table class="antibody-info-table">        <tr><th>Clone:</th><td>MRQ-56</td></tr>        <tr><th>Brand:</th><td>Cell Marque</td></tr>        <tr><th>Host:</th><td>Mouse</td></tr>        <tr><th>Antibody Type:</th><td>Monoclonal</td></tr>        <tr><th>Specialties:</th><td>Hematopathology • Anatomic Pathology</td></tr>        <tr><th>Visualization:</th><td>membranous</td></tr>        <tr><th>Control:</th><td>tonsil, peripheral T-cell lymphoma</td></tr>        <tr><th>Dilution Range:</th><td>1:100-1:500*</td></tr>        <tr>          <td colspan="2" class="antibody-details-cell">            <div class="antibody-vis-label"><strong>Details:</strong></div>            <div class="antibody-desc">CD7 antigen is a 40-kDa cell surface glycoprotein that is a member of the immunoglobulin gene superfamily.1,2While its precise function is not known, it is suggested that CD7 plays a role in T-cell interactions as it is one of the earliest T-cell lineage associated antigens expressed during T-cell ontogeny.2,3CD7 is expressed in thymocytes, mature peripheral T-cells, natural killer cells, and lymphoid and myeloid progenitors.1,2,4</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/2143/CD7_MRQ-56" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','CD7 (MRQ-56) on tonsil.','https://www.cellmarque.com/antibodies/CM/2143/CD7_MRQ-56','#','https://www.cellmarque.com/cmsial-images/TH_107M-2-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-2143-cd7-mrq-56-1BFC904B',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','Y',null,'CM/2143/CD7_MRQ-56');
Insert into WEB.PRODUCTS (DELETED,ACTIVE,PRODUCT_ID,PRODUCT_NAME,PRODUCT_NAME_WEB,SHORT_NAME,PRODUCT_SIPPLIER_ORDER,SUPPLIER_ID,DISCIPLINE,PRODUCT_GROUP,PRODUCT_TYPE,CLASS_ID,CLASS_COLOUR,ABOUT_1,ABOUT_2,PRODUCT_LINK,PRODUCT_ENQUIRE,PRODUCT_IMAGE_LARGE,PRODUCT_IMAGE_SMALL,PRODUCT_IMAGE_1,PRODUCT_IMAGE_2,PRODUCT_IMAGE_3,PRODUCT_IMAGE_4,PRODUCT_PARENT_ID,DATE_CREATED,DATE_DELETED,ANCHOR_ID,PRODUCT_IMAGE_LARGE_WIDTH,PRODUCT_IMAGE_LARGE_HEIGHT,PRODUCT_IMAGE_SMALL_WIDTH,PRODUCT_IMAGE_SMALL_HEIGHT,SUPPLIER_NAME,DISCIPLINE_ID,PRODUCT_GROUP_ID,PRODUCT_TYPE_ID,PRODUCT_GROUP_TYPE_ALT,PRODUCT_GROUP_TYPE_ALT_ID,BUSINESS,PRODUCT_IMAGE_EXTERNAL,PROUDUCT_SKU,SUPPLIER_PRODUCT_ID) values ('N','Y','PRD-7659','SOX-11',null,null,null,'SUP-0003','Histopathology','Antibodies','Reagents',null,null,'<div class="antibody-outer-wrap ">  <div class="antibody-drawer-box">    <div class="antibody-info-table-wrap">      <table class="antibody-info-table">        <tr><th>Clone:</th><td>MRQ-58</td></tr>        <tr><th>Brand:</th><td>Cell Marque</td></tr>        <tr><th>Host:</th><td>Mouse</td></tr>        <tr><th>Antibody Type:</th><td>Monoclonal</td></tr>        <tr><th>Specialties:</th><td>Hematopathology</td></tr>        <tr><th>Visualization:</th><td></td></tr>        <tr><th>Control:</th><td>Mantle cell lymphoma (Nuclear)</td></tr>        <tr><th>Dilution Range:</th><td>1:25-1:100*</td></tr>        <tr>          <td colspan="2" class="antibody-details-cell">            <div class="antibody-vis-label"><strong>Details:</strong></div>            <div class="antibody-desc">SOX-11 which is a member of the SOX (SRY-related HMG-box) family is a transcription factor normally expressed in the developing human central nervous system and plays a role in embryonic cell determination.1,3Studies show that SOX-11 can be used as a marker for mantle cell lymphoma (MCL).2,3</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/2145/SOX-11_MRQ-58" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Nuclear labelling of mantle cell lymphoma by SOX-11 antibody.','https://www.cellmarque.com/antibodies/CM/2145/SOX-11_MRQ-58','#','https://www.cellmarque.com/cmsial-images/TH_382M-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-2145-sox-11-mrq-58-97C0859A',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','Y',null,'CM/2145/SOX-11_MRQ-58');
Insert into WEB.PRODUCTS (DELETED,ACTIVE,PRODUCT_ID,PRODUCT_NAME,PRODUCT_NAME_WEB,SHORT_NAME,PRODUCT_SIPPLIER_ORDER,SUPPLIER_ID,DISCIPLINE,PRODUCT_GROUP,PRODUCT_TYPE,CLASS_ID,CLASS_COLOUR,ABOUT_1,ABOUT_2,PRODUCT_LINK,PRODUCT_ENQUIRE,PRODUCT_IMAGE_LARGE,PRODUCT_IMAGE_SMALL,PRODUCT_IMAGE_1,PRODUCT_IMAGE_2,PRODUCT_IMAGE_3,PRODUCT_IMAGE_4,PRODUCT_PARENT_ID,DATE_CREATED,DATE_DELETED,ANCHOR_ID,PRODUCT_IMAGE_LARGE_WIDTH,PRODUCT_IMAGE_LARGE_HEIGHT,PRODUCT_IMAGE_SMALL_WIDTH,PRODUCT_IMAGE_SMALL_HEIGHT,SUPPLIER_NAME,DISCIPLINE_ID,PRODUCT_GROUP_ID,PRODUCT_TYPE_ID,PRODUCT_GROUP_TYPE_ALT,PRODUCT_GROUP_TYPE_ALT_ID,BUSINESS,PRODUCT_IMAGE_EXTERNAL,PROUDUCT_SKU,SUPPLIER_PRODUCT_ID) values ('N','Y','PRD-7651','Carbonic Anhydrase IX (CA IX)',null,null,null,'SUP-0003','Histopathology','Antibodies','Reagents',null,null,'<div class="antibody-outer-wrap ">  <div class="antibody-drawer-box">    <div class="antibody-info-table-wrap">      <table class="antibody-info-table">        <tr><th>Clone:</th><td>MRQ-54</td></tr>        <tr><th>Brand:</th><td>Cell Marque</td></tr>        <tr><th>Host:</th><td>Mouse</td></tr>        <tr><th>Antibody Type:</th><td>Monoclonal</td></tr>        <tr><th>Specialties:</th><td>Anatomic Pathology</td></tr>        <tr><th>Visualization:</th><td>membranous</td></tr>        <tr><th>Control:</th><td>clear cell renal cell carcinoma, gall bladder epithelium</td></tr>        <tr><th>Dilution Range:</th><td>1:50-1:200*</td></tr>        <tr>          <td colspan="2" class="antibody-details-cell">            <div class="antibody-vis-label"><strong>Details:</strong></div>            <div class="antibody-desc">Carbonic Anhydrase (CA IX) is part of a family of zinc containing metalloproteins that catalyze the reversible hydration of CO2.1Among these, CA IX is anchored to the cell membrane and is expressed in the human gastrointestinal tract, chiefly in the stomach.1Data suggest consistent immunoreactivity for anti-CA IX in clear cell renal cell carcinoma (RCC) making it a useful marker for this type of tumor.2</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/2133/Carbonic-Anhydrase-IX-CA-IX_MRQ-54" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Mouse monoclonal CA IX antibody shows a strong membranous expression of the CA IX protein in renal cell carcinoma.','https://www.cellmarque.com/antibodies/CM/2133/Carbonic-Anhydrase-IX-CA-IX_MRQ-54','#','https://www.cellmarque.com/cmsial-images/TH_379M-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-2133-carbonic-anhydrase-ix-ca-ix-mrq--711CEAD1',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','Y',null,'CM/2133/Carbonic-Anhydrase-IX-CA-IX_MRQ-54');
