   </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/2009/PD-1_NAT105" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Scattered germinal center cells labelled with PD-1 antibody.','https://www.cellmarque.com/antibodies/CM/2009/PD-1_NAT105','#','https://www.cellmarque.com/cmsial-images/TH_315M-9-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-2009-pd-1-nat105-84D808D0',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','Y',null,'CM/2009/PD-1_NAT105');
