dy-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/13/ACTH_polyclonal" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Pituitary cells express anti-ACTH in the cytoplasm.','https://www.cellmarque.com/antibodies/CM/13/ACTH_polyclonal','#','https://www.cellmarque.com/cmsial-images/TH_206A-7-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-13-acth-polyclonal-28A7E198',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','Y',null,'CM/13/ACTH_polyclonal');
Insert into WEB.PRODUCTS (DELETED,ACTIVE,PRODUCT_ID,PRODUCT_NAME,PRODUCT_NAME_WEB,SHORT_NAME,PRODUCT_SIPPLIER_ORDER,SUPPLIER_ID,DISCIPLINE,PRODUCT_GROUP,PRODUCT_TYPE,CLASS_ID,CLASS_COLOUR,ABOUT_1,ABOUT_2,PRODUCT_LINK,PRODUCT_ENQUIRE,PRODUCT_IMAGE_LARGE,PRODUCT_IMAGE_SMALL,PRODUCT_IMAGE_1,PRODUCT_IMAGE_2,PRODUCT_IMAGE_3,PRODUCT_IMAGE_4,PRODUCT_PARENT_ID,DATE_CREATED,DATE_DELETED,ANCHOR_ID,PRODUCT_IMAGE_LARGE_WIDTH,PRODUCT_IMAGE_LARGE_HEIGHT,PRODUCT_IMAGE_SMALL_WIDTH,PRODUCT_IMAGE_SMALL_HEIGHT,SUPPLIER_NAME,DISCIPLINE_ID,PRODUCT_GROUP_ID,PRODUCT_TYPE_ID,PRODUCT_GROUP_TYPE_ALT,PRODUCT_GROUP_TYPE_ALT_ID,BUSINESS,PRODUCT_IMAGE_EXTERNAL,PROUDUCT_SKU,SUPPLIER_PRODUCT_ID) values ('N','Y','PRD-7501','IgD',null,null,null,'SUP-0003','Histopathology','Antibodies','Reagents',null,null,'<div class="antibody-outer-wrap ">  <div class="antibody-drawer-box">    <div class="antibody-info-table-wrap">      <table class="antibody-info-table">        <tr><th>Clone:</th><td>Polyclonal</td></tr>        <tr><th>Brand:</th><td>Cell Marque</td></tr>        <tr><th>Host:</th><td>Rabbit</td></tr>        <tr><th>Antibody Type:</th><td>Polyclonal</td></tr>        <tr><th>Specialties:</th><td>Hematopathology</td></tr>        <tr><th>Visualization:</th><td></td></tr>        <tr><th>Control:</th><td>Tonsil (Cytoplasmic)</td></tr>        <tr><th>Dilution Range:</th><td>1:100-1:500*</td></tr>        <tr>          <td colspan="2" class="antibody-details-cell">            <div class="antibody-vis-label"><strong>Details:</strong></div>            <div class="antibody-desc">The monoclonal antibody against IgD reacts with immunoglobin D delta chains. In tonsil and lymph node, immunohistochemical staining for IgD immunoglobulin heavy chain is usually used to highlight the tonsil and nodal architecture since the IgD antibody stains mantle zone cells in secondary follicles and mantle cells in primary follicles.1It has been reported that IgD can be detected in the surface/cytoplasm of neoplastic cells of common small B lymphoid cell lymphomas, such as small lymphocytic lymphoma, mantle cell lymphoma, marginal zone lymphoma (especially splenic marginal zone lymphoma), and follicular lymphoma.1-2IgD expression in L & P cells of nodular lymphocyte predominant Hodkin lymphoma has been seen in subsets of cases (27% to 71.4%).1-3The IgD positive L & P cells are usually located in the extrafollicular area with a relatively T-cell-rich background.1,3IgD expression is rarely seen in T-cell rich B-cell lymphoma. Studies have demonstrated that Reed-Sternberg cells of classic Hodgkin lymphoma are negative for IgD.1,3IgD multiple myeloma is a rare bone marrow plasma cell dyscrasia and can be identified by the IgD antibody, especially when a dry tap is encountered.4 Note:This product is in obsolescence.IgD (EP173)is available as an alternative.</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/102/IgD_Polyclonal" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','IgD (polyclonal) on lymph node.','https://www.cellmarque.com/antibodies/CM/102/IgD_Polyclonal','#','https://www.cellmarque.com/cmsial-images/TH_268A-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-102-igd-polyclonal-350B72F6',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','Y',null,'CM/102/IgD_Polyclonal');
Insert into WEB.PRODUCTS (DELETED,ACTIVE,PRODUCT_ID,PRODUCT_NAME,PRODUCT_NAME_WEB,SHORT_NAME,PRODUCT_SIPPLIER_ORDER,SUPPLIER_ID,DISCIPLINE,PRODUCT_GROUP,PRODUCT_TYPE,CLASS_ID,CLASS_COLOUR,ABOUT_1,ABOUT_2,PRODUCT_LINK,PRODUCT_ENQUIRE,PRODUCT_IMAGE_LARGE,PRODUCT_IMAGE_SMALL,PRODUCT_IMAGE_1,PRODUCT_IMAGE_2,PRODUCT_IMAGE_3,PRODUCT_IMAGE_4,PRODUCT_PARENT_ID,DATE_CREATED,DATE_DELETED,ANCHOR_ID,PRODUCT_IMAGE_LARGE_WIDTH,PRODUCT_IMAGE_LARGE_HEIGHT,PRODUCT_IMAGE_SMALL_WIDTH,PRODUCT_IMAGE_SMALL_HEIGHT,SUPPLIER_NAME,DISCIPLINE_ID,PRODUCT_GROUP_ID,PRODUCT_TYPE_ID,PRODUCT_GROUP_TYPE_ALT,PRODUCT_GROUP_TYPE_ALT_ID,BUSINESS,PRODUCT_IMAGE_EXTERNAL,PROUDUCT_SKU,SUPPLIER_PRODUCT_ID) values ('N','Y','PRD-7543','Cytokeratin 5 & 6 (D5/16B4) + TTF-1 (8G7G3/1)',null,null,null,'SUP-0003','Histopathology','Antibodies','Reagents',null,null,'<div class="antibody-outer-wrap ">  <div class="antibody-drawer-box">    <div class="antibody-info-table-wrap">      <table class="antibody-info-table">        <tr><th>Clone:</th><td></td></tr>        <tr><th>Brand:</th><td>Cell Marque</td></tr>        <tr><th>Host:</th><td>Mouse</td></tr>        <tr><th>Antibody Type:</th><td>Monoclonal</td></tr>        <tr><th>Specialties:</th><td>None</td></tr>        <tr><th>Visualization:</th><td>cytoplasmic(cytokeratin 5 & 6), nuclear</td></tr>        <tr><th>Control:</th><td>mesothelioma, lung adenocarcinoma</td></tr>        <tr><th>Dilution Range:</th><td>N/A*</td></tr>        <tr>          <td colspan="2" class="antibody-details-cell">            <div class="antibody-vis-label"><strong>Details:</strong></div>            <div class="antibody-desc">Anti-Cytokeratin 5 & 6 is a marker for eptihelioid mesotheliomas. Anti-Cytokeratin 5 & 6 stains the cytoplasm of such cells. Anti-TTF-1 stains the nuclei in the case of lung adenocarcinomas and is negative in nearly all mesotheliomas. The nuclear vs. cytoplasmic staining pattern of this cocktail can be useful in distinguishing between mesothelioma and adenocarcinoma of the lung.1-7</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/184/Cytokeratin-5-6-D5-16B4-TTF-1-8G7G3-1" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Cytokeratin 5 & 6 + TTF-1 (D5/16B4 + 8G7G3/1) on lung.','https://www.cellmarque.com/antibodies/CM/184/Cytokeratin-5-6-D5-16B4-TTF-1-8G7G3-1','#','https://www.cellmarque.com/cmsial-images/TH_902H-0-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-184-cytokeratin-5-6-d5-16b4-ttf-1-8g7-890611FB',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','Y',null,'CM/184/Cytokeratin-5-6-D5-16B4-TTF-1-8G7G3-1');
Insert into WEB.PRODUCTS (DELETED,ACTIVE,PRODUCT_ID,PRODUCT_NAME,PRODUCT_NAME_WEB,SHORT_NAME,PRODUCT_SIPPLIER_ORDER,SUPPLIER_ID,DISCIPLINE,PRODUCT_GROUP,PRODUCT_TYPE,CLASS_ID,CLASS_COLOUR,ABOUT_1,ABOUT_2,PRODUCT_LINK,PRODUCT_ENQUIRE,PRODUCT_IMAGE_LARGE,PRODUCT_IMAGE_SMALL,PRODUCT_IMAGE_1,PRODUCT_IMAGE_2,PRODUCT_IMAGE_3,PRODUCT_IMAGE_4,PRODUCT_PARENT_ID,DATE_CREATED,DATE_DELETED,ANCHOR_ID,PRODUCT_IMAGE_LARGE_WIDTH,PRODUCT_IMAGE_LARGE_HEIGHT,PRODUCT_IMAGE_SMALL_WIDTH,PRODUCT_IMAGE_SMALL_HEIGHT,SUPPLIER_NAME,DISCIPLINE_ID,PRODUCT_GROUP_ID,PRODUCT_TYPE_ID,PRODUCT_GROUP_TYPE_ALT,PRODUCT_GROUP_TYPE_ALT_ID,BUSINESS,PRODUCT_IMAGE_EXTERNAL,PROUDUCT_SKU,SUPPLIER_PRODUCT_ID) values ('N','Y','PRD-7544','CD30',null,null,null,'SUP-0003','Histopathology','Antibodies','Reagents',null,null,'<div class="antibody-outer-wrap ">  <div class="antibody-drawer-box">    <div class="antibody-info-table-wrap">      <table class="antibody-info-table">        <tr><th>Clone:</th><td>Ber-H2</td></tr>        <tr><th>Brand:</th><td>Cell Marque</td></tr>        <tr><th>Host:</th><td>Mouse</td></tr>        <tr><th>Antibody Type:</th><td>Monoclonal</td></tr>        <tr><th>Specialties:</th><td>Hematopathology</td></tr>        <tr><th>Visualization:</th><td></td></tr>        <tr><th>Control:</th><td>Classic Hodgkin Lymphoma (Membranous); Lymphoma (Membranous)</td></tr>        <tr><th>Dilution Range:</th><td>1:50-1:200*</td></tr>        <tr>          <td colspan="2" class="antibody-details-cell">            <div class="antibody-vis-label"><strong>Details:</strong></div>            <div class="antibody-desc">Anti-CD30 detects a formalin-resistant epitope that is expressed by Reed-Sternberg cells in classic Hodgkin lymphoma, the majority of anaplastic large cell lymphomas, primary cutaneous CD30 positive T-cell lymphoproliferative disorders,1-3and in embryonal carcinomas.4Occasionally diffuse large B-cell lymphoma stains with this antibody.3This antibody also stains plasma cells in paraffin-embedded tissue as well as reactive immunoblasts. The staining pattern of anti-CD30 in lymphoma and embryonal carcinoma is different, with the former being membranous and exhibiting Golgi zone accentuation in location, and the latter being membranous only.4</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/189/CD30_Ber-H2" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','CD30 (Ber-H2) on lymph node, ALCL.','https://www.cellmarque.com/antibodies/CM/189/CD30_Ber-H2','#','https://www.cellmarque.com/cmsial-images/TH_130M-9-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-189-cd30-ber-h2-E3085D15',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','Y',null,'CM/189/CD30_Ber-H2');
Insert into WEB.PRODUCTS (DELETED,ACTIVE,PRODUCT_ID,PRODUCT_NAME,PRODUCT_NAME_WEB,SHORT_NAME,PRODUCT_SIPPLIER_ORDER,SUPPLIER_ID,DISCIPLINE,PRODUCT_GROUP,PRODUCT_TYPE,CLASS_ID,CLASS_COLOUR,ABOUT_1,ABOUT_2,PRODUCT_LINK,PRODUCT_ENQUIRE,PRODUCT_IMAGE_LARGE,PRODUCT_IMAGE_SMALL,PRODUCT_IMAGE_1,PRODUCT_IMAGE_2,PRODUCT_IMAGE_3,PRODUCT_IMAGE_4,PRODUCT_PARENT_ID,DATE_CREATED,DATE_DELETED,ANCHOR_ID,PRODUCT_IMAGE_LARGE_WIDTH,PRODUCT_IMAGE_LARGE_HEIGHT,PRODUCT_IMAGE_SMALL_WIDTH,PRODUCT_IMAGE_SMALL_HEIGHT,SUPPLIER_NAME,DISCIPLINE_ID,PRODUCT_GROUP_ID,PRODUCT_TYPE_ID,PRODUCT_GROUP_TYPE_ALT,PRODUCT_GROUP_TYPE_ALT_ID,BUSINESS,PRODUCT_IMAGE_EXTERNAL,PROUDUCT_SKU,SUPPLIER_PRODUCT_ID) values ('N','Y','PRD-7660','CD23',null,null,null,'SUP-0003','Histopathology','Antibodies','Reagents',null,null,'<div class="antibody-outer-wrap ">  <div class="antibody-drawer-box">    <div class="antibody-info-table-wrap">      <table class="antibody-info-table">        <tr><th>Clone:</th><td>MRQ-57</td></tr>        <tr><th>Brand:</th><td>Cell Marque</td></tr>        <tr><th>Host:</th><td>Mouse</td></tr>        <tr><th>Antibody Type:</th><td>Monoclonal</td></tr>        <tr><th>Specialties:</th><td>Hematopathology</td></tr>        <tr><th>Visualization:</th><td></td></tr>        <tr><th>Control:</th><td>Tonsil, Lymph Node (Membranous); Chronic lymphocytic leukemia/Small lymphocytic lymphoma (Membranous)</td></tr>        <tr><th>Dilution Range:</th><td>1:100-1:500*</td></tr>        <tr>          <td colspan="2" class="antibody-details-cell">            <div class="antibody-vis-label"><strong>Details:</strong></div>            <div class="antibody-desc">CD23 antigen is a 45-60 kDa membrane glycoprotein identified as a low affinity receptor for IgE production as well as a receptor for lymphocyte growth factor. CD23 is found in some mature B-cell lymphomas and in Reed-Sternberg cells in Hodgkin disease.1Follicular dendritic cells and some activated B-cells within germinal centers express CD23 in high density and mantle zone B-cells are stained weakly.2The majority of chronic lymphocytic leukemias/small lymphocytic lymphomas are CD23 positive, whereas mantle cell lymphomas are generally negative, so this marker is useful when applied with other markers to separate the small cell lymphomas.2Precursor B and T lymphomas, myeloid neoplasms, and mature T-cell lymphomas are CD23 negative and other small cell lymphomas are occasionally positive.3CD23 is also positive on activated mature B-cells expressing IgM or IgD, monocytes/macrophages, follicular dendritic cells, T-cell subsets, eosinophils, Langerhans cells and small lymphocytic lymphoma/chronic lymphocytic leukemia (SLL/CLL). Note:This product is in obsolescence.CD23 (1B12)is available as an alternative.</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/2146/CD23_MRQ-57" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','CD23 (MRQ-57) on lymph node.','https://www.cellmarque.com/antibodies/CM/2146/CD23_MRQ-57','#','https://www.cellmarque.com/cmsial-images/TH_123M-2-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-2146-cd23-mrq-57-EC5458E6',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','Y',null,'CM/2146/CD23_MRQ-57');
Insert into WEB.PRODUCTS (DELETED,ACTIVE,PRODUCT_ID,PRODUCT_NAME,PRODUCT_NAME_WEB,SHORT_NAME,PRODUCT_SIPPLIER_ORDER,SUPPLIER_ID,DISCIPLINE,PRODUCT_GROUP,PRODUCT_TYPE,CLASS_ID,CLASS_COLOUR,ABOUT_1,ABOUT_2,PRODUCT_LINK,PRODUCT_ENQUIRE,PRODUCT_IMAGE_LARGE,PRODUCT_IMAGE_SMALL,PRODUCT_IMAGE_1,PRODUCT_IMAGE_2,PRODUCT_IMAGE_3,PRODUCT_IMAGE_4,PRODUCT_PARENT_ID,DATE_CREATED,DATE_DELETED,ANCHOR_ID,PRODUCT_IMAGE_LARGE_WIDTH,PRODUCT_IMAGE_LARGE_HEIGHT,PRODUCT_IMAGE_SMALL_WIDTH,PRODUCT_IMAGE_SMALL_HEIGHT,SUPPLIER_NAME,DISCIPLINE_ID,PRODUCT_GROUP_ID,PRODUCT_TYPE_ID,PRODUCT_GROUP_TYPE_ALT,PRODUCT_GROUP_TYPE_ALT_ID,BUSINESS,PRODUCT_IMAGE_EXTERNAL,PROUDUCT_SKU,SUPPLIER_PRODUCT_ID) values ('N','Y','PRD-7661','SOX-10',null,null,null,'SUP-0003','Histopathology','Antibodies','Reagents',null,null,'<div class="antibody-outer-wrap ">  <div class="antibody-drawer-box">    <div class="antibody-info-table-wrap">      <table class="antibody-info-table">        <tr><th>Clone:</th><td>Polyclonal</td></tr>        <tr><th>Brand:</th><td>Cell Marque</td></tr>        <tr><th>Host:</th><td>Rabbit</td></tr>        <tr><th>Antibody Type:</th><td>Polyclonal</td></tr>        <tr><th>Specialties:</th><td>Dermatopathology</td></tr>        <tr><th>Visualization:</th><td></td></tr>        <tr><th>Control:</th><td>Melanoma (Nuclear); Schwannoma (Nuclear); Skin Melanocytes (Nuclear)</td></tr>        <tr><th>Dilution Range:</th><td>1:25-1:100*</td></tr>        <tr>          <td colspan="2" class="antibody-details-cell">            <div class="antibody-vis-label"><strong>Details:</strong></div>            <div class="antibody-desc">Sry-related HMG-BOX gene 10, SOX-10, is a transcription factor involved in neural crest and peripheral nervous system development, and acts as a nucleocytoplasmic shuttle protein.1SOX-10 is expressed in melanocytic lineages, and is a sensitive marker of melanoma for conventional, and desmoplastic subtypes.2-3In normal tissues, SOX-10 is expressed in melanocytes, and myoepithelial cells.4 Note:This product has been discontinued.SOX-10 (EP268)is available as an alternative.</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/2147/SOX-10_Polyclonal" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Nuclear labelling of melanoma tumor cells by SOX-10 antibody.','https://www.cellmarque.com/antibodies/CM/2147/SOX-10_Polyclonal','#','https://www.cellmarque.com/cmsial-images/TH_383A-7-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-2147-sox-10-polyclonal-F9B6A27B',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','Y',null,'CM/2147/SOX-10_Polyclonal');
