bin.3Anti-CD163 labels cells of monocytic-macrophage lineage, with expression in bone marrow3and histiocytic neoplasms.4</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/2010/CD163_MRQ-26" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','CD163 (MRQ-26) on placenta.','https://www.cellmarque.com/antibodies/CM/2010/CD163_MRQ-26','#','https://www.cellmarque.com/cmsial-images/TH_163M-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-2010-cd163-mrq-26-6FAA1DE9',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','Y',null,'CM/2010/CD163_MRQ-26');
Insert into WEB.PRODUCTS (DELETED,ACTIVE,PRODUCT_ID,PRODUCT_NAME,PRODUCT_NAME_WEB,SHORT_NAME,PRODUCT_SIPPLIER_ORDER,SUPPLIER_ID,DISCIPLINE,PRODUCT_GROUP,PRODUCT_TYPE,CLASS_ID,CLASS_COLOUR,ABOUT_1,ABOUT_2,PRODUCT_LINK,PRODUCT_ENQUIRE,PRODUCT_IMAGE_LARGE,PRODUCT_IMAGE_SMALL,PRODUCT_IMAGE_1,PRODUCT_IMAGE_2,PRODUCT_IMAGE_3,PRODUCT_IMAGE_4,PRODUCT_PARENT_ID,DATE_CREATED,DATE_DELETED,ANCHOR_ID,PRODUCT_IMAGE_LARGE_WIDTH,PRODUCT_IMAGE_LARGE_HEIGHT,PRODUCT_IMAGE_SMALL_WIDTH,PRODUCT_IMAGE_SMALL_HEIGHT,SUPPLIER_NAME,DISCIPLINE_ID,PRODUCT_GROUP_ID,PRODUCT_TYPE_ID,PRODUCT_GROUP_TYPE_ALT,PRODUCT_GROUP_TYPE_ALT_ID,BUSINESS,PRODUCT_IMAGE_EXTERNAL,PROUDUCT_SKU,SUPPLIER_PRODUCT_ID) values ('N','Y','PRD-7580','Thrombomodulin',null,null,null,'SUP-0003','Histopathology','Antibodies','Reagents',null,null,'<div class="antibody-outer-wrap ">  <div class="antibody-drawer-box">    <div class="antibody-info-table-wrap">      <table class="antibody-info-table">        <tr><th>Clone:</th><td>1009</td></tr>        <tr><th>Brand:</th><td>Cell Marque</td></tr>        <tr><th>Host:</th><td>Mouse</td></tr>        <tr><th>Antibody Type:</th><td>Monoclonal</td></tr>        <tr><th>Specialties:</th><td>Anatomic Pathology</td></tr>        <tr><th>Visualization:</th><td>cytoplasmic, membranous</td></tr>        <tr><th>Control:</th><td>bladder, mesothelioma</td></tr>        <tr><th>Dilution Range:</th><td>1:25-1:100*</td></tr>        <tr>          <td colspan="2" class="antibody-details-cell">            <div class="antibody-vis-label"><strong>Details:</strong></div>            <div class="antibody-desc">Thrombomodulin is a transmembrane glycoprotein composed of 575 amino acids (molecular weight 75 kD) with natural anticoagulant properties. It is normally expressed by a restricted number of cells, such as endothelial and mesothelial cells. In addition, synovial lining and syncytiotrophoblasts of human placenta also express thrombomodulin.1-3Anti-thrombomodulin has demonstrated positivity in benign vascular tumors such as hemangioma and most malignant vascular tumors (Kaposi’s sarcoma and epitheliod hemangioendothelioma).1-2Hence, anti-thrombomodulin serves as a sensitive marker for lymphatic endothelial cells and their tumors.1-2There has also been recent interest in the use of anti-thrombomodulin as an immunohiostochemical marker for mesothelial cells and malignant mesotheliomas.3-8Anti-thrombomodulin is immunoexpressed in a variety of other tumors including urothelial cell carcinomas.9,10</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/2011/Thrombomodulin_1009" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Membranous labelling of urothelial transitional cell carcinoma by thrombomodulin antibody.','https://www.cellmarque.com/antibodies/CM/2011/Thrombomodulin_1009','#','https://www.cellmarque.com/cmsial-images/TH_339M-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-2011-thrombomodulin-1009-836488F5',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','Y',null,'CM/2011/Thrombomodulin_1009');
