e">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','IgM (polyclonals) on endometrium.','https://www.cellmarque.com/antibodies/CM/104/IgM_polyclonal','#','https://www.cellmarque.com/cmsial-images/TH_270A-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-104-igm-polyclonal-A05A4369',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','Y',null,'CM/104/IgM_polyclonal');
