v>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/191/p27Kip1_SX53G8" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','p27 antibody labels the nuclei of most mature lymphocyte in the paracrotical and intracortical region, as well as squamous epithelial nuclei.','https://www.cellmarque.com/antibodies/CM/191/p27Kip1_SX53G8','#','https://www.cellmarque.com/cmsial-images/TH_427M-9-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-191-p27kip1-sx53g8-85E46D9A',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','Y',null,'CM/191/p27Kip1_SX53G8');
