in characterizing a lesion’s growth fraction.</div>          </td>        </tr>      </table>    </div>    <div class="antibody-link-button">      <a href="https://www.cellmarque.com/antibodies/CM/108/Ki-67_SP6" target="_blank" title="View Cell Marque Product Page">        <img src="#WORKSPACE_FILES#assets/images/Scientific/suppliers/Cell_Marque/cell_marque-logo.png" alt="View Product" class="product-link-image">      </a>    </div>  </div></div>','Ki-67 (SP6) on tonsil.','https://www.cellmarque.com/antibodies/CM/108/Ki-67_SP6','#','https://www.cellmarque.com/cmsial-images/TH_275R-1-ihc-01.jpg',null,null,null,null,null,null,to_date('24-APR-26','DD-MON-RR'),null,'_cm-108-ki-67-sp6-78A8903C',null,null,null,null,'Cell Marque','DIS-0001','PRG-0001','PTY-0003',null,null,'Syntec Scientific','Y',null,'CM/108/Ki-67_SP6');
